import{z as t}from"zod";export const RuleSentinelIssueSchema=t.object({severity:t.enum(["error","warning","info"]),scope:t.enum(["global","chapter","paragraph"]),dimension:t.string().min(1),message:t.string().min(1),repairScope:t.enum(["local","structural"]),location:t.string(),label:t.string().optional(),suggestion:t.string().optional()}),RuleSentinelInputSchema=t.object({chapterContent:t.string().min(1),chapterIndex:t.number().int().min(1).optional(),currentState:t.string().optional(),chapterSummaries:t.string().optional(),storyBible:t.string().optional(),assetCatalog:t.any().optional()}),RuleAuditResultSchema=t.object({issues:t.array(RuleSentinelIssueSchema),detectorCount:t.number().int().min(0),summary:t.string()});
